import{_ as s,o as a,c as i,a2 as t}from"./chunks/framework.m9rfQn3T.js";const d=JSON.parse('{"title":"webpack热更新原理","description":"","frontmatter":{"title":"webpack热更新原理","date":"2020-06-17T13:36:05.000Z","permalink":"/pages/c6cc139500985/","categories":["面试题","Webpack"],"tags":[null]},"headers":[],"relativePath":"10.面试题/41.Webpack/06.webpack热更新原理.md","filePath":"10.面试题/41.Webpack/06.webpack热更新原理.md","lastUpdated":1782538095000}'),l={name:"10.面试题/41.Webpack/06.webpack热更新原理.md"};function n(p,e,h,r,k,c){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>HMR 其实就是 Hot Module Replacement,可以理解成模块热替换，指在应用程序运行过程中，替换、添加、删除模块，而无需重新刷新整个应用</p><p>&lt;!-- more --&gt;</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> webpack</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> require</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;webpack&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">module</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">exports</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  devServer: {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    hot: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre></div><h2 id="原理" tabindex="-1">原理 <a class="header-anchor" href="#原理" aria-label="Permalink to &quot;原理&quot;">​</a></h2><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210617134036.png" alt="20210617134036"></p><ul><li>Webpack Compile:将 js 代码编译成 bundle.js</li><li>HMR Server: 用来将热更新的文件输出给 HMR Runtime</li><li>Bundle Server: 静态资源文件服务器，提供文件访问路径</li><li>HMR Runtime: socket 服务器，会被注入到浏览器，更新文件的变化</li><li>bundle.js 构建输出的文件</li><li>在 HMR Runtime 和 HMR Server 之间建立 websocket，即可实时更新文件变化</li></ul><p>上图分为两个阶段：</p><ul><li>启动阶段： 1-2-A-B</li></ul><p>在编写未经过 webpack 打包的源代码后，Webpack Compile 将源代码和 HMR Runtime 一起编译成 bundle 文件，传输给 Bundle Server 静态资源服务器</p><ul><li>更新阶段： 1-2-3-4</li></ul><p>当某一个文件或者模块发生变化时，webpack 监听到文件变化对文件重新编译打包，编译生成唯一的 hash 值，这个 hash 值用来作为下一次热更新的标识</p><p>根据变化的内容生成两个补丁文件：manifest（包含了 hash 和 chundId，用来说明变化的内容）和 chunk.js 模块</p><p>由于 socket 服务器在 HMR Runtime 和 HMR Server 之间建立 websocket 链接，当文件发生改动的时候，服务端会向浏览器推送一条消息，消息包含文件改动后生成的 hash 值，如下图的 h 属性，作为下一次热更细的标识</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210617134633.png" alt="20210617134633"></p><p>在浏览器接受到这条消息之前，浏览器已经在上一次 socket 消息中已经记住了此时的 hash 标识，这时候我们会创建一个 ajax 去服务端请求获取到变化内容的 manifest 文件</p><p>mainfest 文件包含重新 build 生成的 hash 值，以及变化的模块，对应上图的 c 属性</p><p>浏览器根据 manifest 文件获取模块变化的内容，从而触发 render 流程，实现局部模块更新</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210617134710.png" alt="20210617134710"></p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><ul><li>通过 webpack-dev-server 创建两个服务器：提供静态资源的服务（express）和 Socket 服务</li><li>express server 负责直接提供静态资源的服务（打包后的资源直接被浏览器请求和解析）</li><li>socket server 是一个 websocket 的长连接，双方可以通信</li><li>当 socket server 监听到对应的模块发生变化时，会生成两个文件.json（manifest 文件）和.js 文件（update chunk）</li><li>通过长连接，socket server 可以直接将这两个文件主动发送给客户端（浏览器）</li><li>浏览器拿到两个新的文件后，通过 HMR runtime 机制，加载这两个文件，并且针对修改的模块进行更新</li></ul><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="https://vue3js.cn/interview/webpack/HMR.html" target="_blank" rel="noreferrer">https://vue3js.cn/interview/webpack/HMR.html</a></li><li><a href="https://github.com/Jocs/jocs.github.io/issues/15" target="_blank" rel="noreferrer">https://github.com/Jocs/jocs.github.io/issues/15</a></li><li><a href="https://zhuanlan.zhihu.com/p/30669007" target="_blank" rel="noreferrer">https://zhuanlan.zhihu.com/p/30669007</a></li></ul>`,23)])])}const u=s(l,[["render",n]]);export{d as __pageData,u as default};
